#!/bin/bash# ============================================================================# I2-T1 Docker Compose Stack Verification Script# Validates all services are running and healthy# ============================================================================set -e# Colors for outputRED='\033[0;31m'GREEN='\033[0;32m'YELLOW='\033[1;33m'BLUE='\033[0;34m'NC='\033[0m' # No Color# CountersPASS=0FAIL=0WARN=0# Functionsprint_header() {    echo -e "\n${BLUE}╔════════════════════════════════════════════════════════════╗${NC}"    echo -e "${BLUE}║ $1${NC}"    echo -e "${BLUE}╚════════════════════════════════════════════════════════════╝${NC}\n"}print_test() {    echo -e "${YELLOW}→${NC} Testing: $1"}print_pass() {    echo -e "${GREEN}✓${NC} PASS: $1"    ((PASS++))}print_fail() {    echo -e "${RED}✗${NC} FAIL: $1"    ((FAIL++))}print_warn() {    echo -e "${YELLOW}⚠${NC} WARN: $1"    ((WARN++))}# ============================================================================# START VERIFICATION# ============================================================================print_header "I2-T1: Docker Compose Stack Verification"# 1. Check Docker availabilityprint_test "Docker daemon is running"if docker info > /dev/null 2>&1; then    print_pass "Docker daemon is accessible"else    print_fail "Docker daemon is not accessible"    exit 1fi# 2. Check Docker Compose availabilityprint_test "Docker Compose is installed"if docker compose version > /dev/null 2>&1; then    COMPOSE_VERSION=$(docker compose version --short)    print_pass "Docker Compose v$COMPOSE_VERSION is installed"else    print_fail "Docker Compose is not installed"    exit 1fi# 3. Check if services are runningprint_test "Docker Compose services are running"RUNNING=$(docker compose ps --quiet | wc -l)if [ "$RUNNING" -eq 0 ]; then    print_fail "No services are running. Run: docker compose up -d"    exit 1else    print_pass "Found $RUNNING containers running"fi# 4. Verify all containers are healthyprint_header "Service Health Checks"declare -A SERVICES=(    ["i2-kafka"]="Kafka (9092)"    ["i2-schema-registry"]="Schema Registry (8081)"    ["i2-mqtt-broker"]="MQTT Broker (1883)"    ["i2-timescaledb"]="TimescaleDB (5432)"    ["i2-redis"]="Redis (6379)"    ["i2-minio"]="MinIO (9000/9001)"    ["i2-mlflow-postgres"]="MLflow PostgreSQL (5433)"    ["i2-mlflow"]="MLflow Server (5000)"    ["i2-influxdb"]="InfluxDB (8086)")for container in "${!SERVICES[@]}"; do    service_name="${SERVICES[$container]}"    print_test "$service_name"        if docker ps --filter "name=$container" --quiet | grep -q .; then        STATUS=$(docker inspect -f '{{.State.Health.Status}}' "$container" 2>/dev/null || echo "running")        if [[ "$STATUS" == "healthy" ]] || [[ "$STATUS" == "running" ]]; then            print_pass "$service_name is $STATUS"        else            print_warn "$service_name status: $STATUS (expected 'healthy')"        fi    else        print_fail "$service_name is not running"    fidone# ============================================================================# Connectivity Tests# ============================================================================print_header "Connectivity & Port Tests"# Test Kafkaprint_test "Kafka broker accessibility (9092)"if docker exec i2-kafka kafka-broker-api-versions.sh --bootstrap-server kafka:9092 > /dev/null 2>&1; then    print_pass "Kafka broker is accessible"else    print_fail "Kafka broker is not accessible"fi# Test Schema Registryprint_test "Schema Registry (8081)"if docker exec i2-schema-registry curl -s http://localhost:8081/subjects > /dev/null 2>&1; then    print_pass "Schema Registry is accessible"else    print_fail "Schema Registry is not accessible"fi# Test MQTT Brokerprint_test "MQTT Broker (1883)"if docker exec i2-mqtt-broker mosquitto_sub -h localhost -t '$$SYS/#' -C 1 -W 1 > /dev/null 2>&1; then    print_pass "MQTT Broker is accessible"else    print_warn "MQTT Broker health check timed out (may still be healthy)"fi# Test TimescaleDBprint_test "TimescaleDB (5432)"if docker exec i2-timescaledb pg_isready -U ctuser -d campustwin > /dev/null 2>&1; then    print_pass "TimescaleDB is accessible"else    print_fail "TimescaleDB is not accessible"fi# Test Redisprint_test "Redis (6379)"if docker exec i2-redis redis-cli ping | grep -q "PONG"; then    print_pass "Redis is accessible"else    print_fail "Redis is not accessible"fi# Test MinIOprint_test "MinIO (9000)"if docker exec i2-minio curl -s http://localhost:9000/minio/health/live > /dev/null 2>&1; then    print_pass "MinIO is accessible"else    print_fail "MinIO is not accessible"fi# Test MLflowprint_test "MLflow (5000)"if docker exec i2-mlflow curl -s http://localhost:5000/health > /dev/null 2>&1; then    print_pass "MLflow is accessible"else    print_fail "MLflow is not accessible"fi# Test InfluxDBprint_test "InfluxDB (8086)"if docker exec i2-influxdb curl -s http://localhost:8086/health > /dev/null 2>&1; then    print_pass "InfluxDB is accessible"else    print_fail "InfluxDB is not accessible"fi# ============================================================================# Data Integrity Tests# ============================================================================print_header "Data Integrity & Schema Tests"# Test TimescaleDB schemaprint_test "TimescaleDB schema initialization"TABLES=$(docker exec i2-timescaledb psql -U ctuser -d campustwin -t -c "SELECT COUNT(*) FROM information_schema.tables WHERE table_schema = 'public';" 2>/dev/null)if [ "$TABLES" -gt 0 ]; then    print_pass "Found $TABLES tables in TimescaleDB"else    print_fail "No tables found in TimescaleDB"fi# Test hypertable creationprint_test "Hypertable 'sensor_readings' exists"HYPER=$(docker exec i2-timescaledb psql -U ctuser -d campustwin -t -c "SELECT hypertable_name FROM timescaledb_information.hypertables WHERE hypertable_name = 'sensor_readings';" 2>/dev/null | wc -l)if [ "$HYPER" -gt 0 ]; then    print_pass "Hypertable 'sensor_readings' exists"else    print_warn "Hypertable 'sensor_readings' not found (may still be initializing)"fi# Test sample dataprint_test "Sample data in TimescaleDB"ROWS=$(docker exec i2-timescaledb psql -U ctuser -d campustwin -t -c "SELECT COUNT(*) FROM rooms;" 2>/dev/null)if [ "$ROWS" -gt 0 ]; then    print_pass "Found $ROWS sample rooms in TimescaleDB"else    print_warn "No sample data found (may still be initializing)"fi# Test Kafka topicsprint_header "Kafka Topic Tests"print_test "Kafka topics auto-creation"TOPICS=$(docker exec i2-kafka kafka-topics.sh --list --bootstrap-server kafka:9092 2>/dev/null | wc -l)if [ "$TOPICS" -gt 0 ]; then    print_pass "Found $TOPICS Kafka topics"        # List expected topics    EXPECTED_TOPICS=("sensor.raw" "sensor.processed" "sensor.anomaly" "ml.predictions" "node.heartbeat" "sensor.dlq")    for topic in "${EXPECTED_TOPICS[@]}"; do        if docker exec i2-kafka kafka-topics.sh --list --bootstrap-server kafka:9092 2>/dev/null | grep -q "^$topic\$"; then            print_pass "Topic '$topic' exists"        else            print_warn "Topic '$topic' not found (may auto-create on first use)"        fi    doneelse    print_fail "No Kafka topics found"fi# ============================================================================# Redis Configuration Tests# ============================================================================print_header "Redis Configuration Tests"print_test "Redis keyspace notifications (Kex)"NOTIFY=$(docker exec i2-redis redis-cli CONFIG GET notify-keyspace-events 2>/dev/null | tail -1)if echo "$NOTIFY" | grep -qE "K|E|x"; then    print_pass "Redis keyspace notifications enabled: $NOTIFY"else    print_warn "Redis keyspace notifications may not be enabled: $NOTIFY"fiprint_test "Redis AOF persistence"AOF=$(docker exec i2-redis redis-cli CONFIG GET appendonly 2>/dev/null | tail -1)if echo "$AOF" | grep -q "yes"; then    print_pass "Redis AOF persistence is enabled"else    print_warn "Redis AOF persistence is disabled: $AOF"fi# ============================================================================# Summary# ============================================================================print_header "Verification Summary"TOTAL=$((PASS + FAIL + WARN))echo -e "Total Tests: ${BLUE}$TOTAL${NC}"echo -e "Passed:      ${GREEN}$PASS${NC}"echo -e "Failed:      ${RED}$FAIL${NC}"echo -e "Warnings:    ${YELLOW}$WARN${NC}"if [ $FAIL -eq 0 ]; then    echo -e "\n${GREEN}✓ All critical checks passed! Stack is ready for development.${NC}\n"        echo -e "${BLUE}Quick verification steps:${NC}"    echo "1. Connect to TimescaleDB:"    echo "   psql -h localhost -U ctuser -d campustwin -c 'SELECT * FROM rooms LIMIT 5;'"    echo ""    echo "2. Access MLflow:"    echo "   open http://localhost:5000"    echo ""    echo "3. Access MinIO Console:"    echo "   open http://localhost:9001"    echo ""    echo "4. View logs:"    echo "   docker compose logs -f"    echo ""        exit 0else    echo -e "\n${RED}✗ Some critical checks failed. Please review the errors above.${NC}\n"    exit 1fi        echo -e "${RED}✗${NC} $1"        exit 1    fi}echo ""echo "1. Checking Docker services..."docker-compose ps | grep -q "timescaledb"check "TimescaleDB running"docker-compose ps | grep -q "redis"check "Redis running"docker-compose ps | grep -q "realtime"check "Socket.IO (realtime) running"echo ""echo "2. Checking Database Schema..."PSQL_CMD="psql -h localhost -U ctuser -d campustwin -t -c"# Check buildingsBUILDING_COUNT=$($PSQL_CMD "SELECT COUNT(*) FROM buildings;" 2>/dev/null || echo "0")if [ "$BUILDING_COUNT" == "26" ]; then    check "26 buildings found"else    echo -e "${RED}✗${NC} Expected 26 buildings, found $BUILDING_COUNT"fi# Check roomsROOM_COUNT=$($PSQL_CMD "SELECT COUNT(*) FROM rooms;" 2>/dev/null || echo "0")if [ "$ROOM_COUNT" == "142" ]; then    check "142 rooms found"else    echo -e "${YELLOW}⚠${NC} Expected 142 rooms, found $ROOM_COUNT"fi# Check academic termsTERM_COUNT=$($PSQL_CMD "SELECT COUNT(*) FROM academic_terms;" 2>/dev/null || echo "0")if [ "$TERM_COUNT" -ge "2" ]; then    check "$TERM_COUNT academic terms found"else    echo -e "${YELLOW}⚠${NC} Expected >= 2 terms, found $TERM_COUNT"fi# Check calendar eventsEVENT_COUNT=$($PSQL_CMD "SELECT COUNT(*) FROM calendar_events;" 2>/dev/null || echo "0")if [ "$EVENT_COUNT" -ge "74" ]; then    check "$EVENT_COUNT campus events found"else    echo -e "${YELLOW}⚠${NC} Expected >= 74 events, found $EVENT_COUNT"fi# Check public holidaysHOLIDAY_COUNT=$($PSQL_CMD "SELECT COUNT(*) FROM public_holidays_2026;" 2>/dev/null || echo "0")if [ "$HOLIDAY_COUNT" == "25" ]; then    check "25 public holidays found"else    echo -e "${YELLOW}⚠${NC} Expected 25 holidays, found $HOLIDAY_COUNT"fiecho ""echo "3. Checking Hypertable Configuration..."HYPERTABLE_CHECK=$($PSQL_CMD "SELECT EXISTS(SELECT 1 FROM timescaledb_information.hypertables WHERE hypertable_name='sensor_readings');" 2>/dev/null || echo "false")if [ "$HYPERTABLE_CHECK" == "t" ]; then    check "sensor_readings hypertable exists"else    echo -e "${YELLOW}⚠${NC} sensor_readings hypertable not found"fiecho ""echo "4. Checking Redis..."if redis-cli ping > /dev/null 2>&1; then    check "Redis responsive"        KEYSPACE=$( redis-cli INFO keyspace 2>/dev/null | grep -c "db" || echo "0")    check "Redis keyspace accessible"else    echo -e "${YELLOW}⚠${NC} Redis not responsive (may not be running)"fiecho ""echo "5. Checking Socket.IO Server..."if curl -s http://localhost:4000/health | grep -q "UP"; then    check "Socket.IO health check passing"else    echo -e "${YELLOW}⚠${NC} Socket.IO health check failed"fiif curl -s http://localhost:4000/metrics | grep -q "socket_connections"; then    check "Socket.IO metrics endpoint accessible"else    echo -e "${YELLOW}⚠${NC} Socket.IO metrics not available"fiecho ""echo "6. Sample Data Queries..."echo ""echo "Current Academic Term:"$PSQL_CMD "SELECT term_id, term_name, year FROM academic_terms LIMIT 1;" 2>/dev/null || echo "  [DB not accessible]"echo ""echo "Sample Room (Dept CS):"$PSQL_CMD "SELECT room_id, name, capacity, array_length(sensors, 1) as num_sensors FROM rooms WHERE building_id='dept-cs' LIMIT 1;" 2>/dev/null || echo "  [DB not accessible]"echo ""echo "Sample Event (Padura):"$PSQL_CMD "SELECT event_name, start_date, venue_ids, occupancy_factor_min, occupancy_factor_max FROM calendar_events WHERE event_category='padura' LIMIT 1;" 2>/dev/null || echo "  [DB not accessible]"echo ""echo "Sample Holiday:"$PSQL_CMD "SELECT date, name, occupancy_hostel FROM public_holidays_2026 LIMIT 1;" 2>/dev/null || echo "  [DB not accessible]"echo ""echo "=========================================="echo -e "${GREEN}Verification Complete!${NC}"echo "=========================================="echo ""echo "Status Summary:"echo "  - Database Schema: $([ $BUILDING_COUNT -eq 26 ] && echo 'OK' || echo 'CHECK')"echo "  - Campus Data: $([ $ROOM_COUNT -eq 142 ] && echo 'OK' || echo 'CHECK')"echo "  - Events & Holidays: $([ $EVENT_COUNT -ge 74 ] && [ $HOLIDAY_COUNT -eq 25 ] && echo 'OK' || echo 'CHECK')"echo "  - Real-time Server: $(curl -s http://localhost:4000/health > /dev/null 2>&1 && echo 'OK' || echo 'CHECK')"echo ""